args.sparql:
SELECT ?person ?personLabel WHERE {
  ?person wdt:P31 wd:Q5 .
  ?person wdt:P27 wd:Q801 .
  ?person wdt:P140 wd:Q9268 .
  ?person wdt:P106 ?occupation1 .
  ?occupation1 wdt:P279* wd:Q639669 .
  ?person wdt:P106 ?occupation2 .
  ?occupation2 wdt:P279* wd:Q975105 .
  OPTIONAL { ?person rdfs:label ?personLabel . FILTER(lang(?personLabel) = "en") }
}
